// Generated by the Infrix Visual Workflow Studio (nextux-12).
// Flow: Regulated escrow  (network: local)
//
// SAFE BY CONSTRUCTION: every action is dry-run first, and every
// state-mutating action is run only after an explicit, input-bound
// approval. This code never skips a dry-run or an approval, and it
// never targets mainnet.
import { agent } from '@infrix/client';

export async function runRegulatedEscrow(endpoint: string) {
  const client = new agent.InfrixAgentClient({ endpoint });
  const network = "local"; // never 'mainnet'

  // Run the governed escrow
  {
    const action = "workflow.execute";
    const input = {"goal":"run a governed escrow and prove it","mode":"local"};
    // 1) Always dry-run to preview exactly what would happen.
    const preview = await client.dryRun(action, input);
    if (!preview.ok) throw new Error('dry-run failed: ' + action);
    // 2) If the action needs approval, obtain an input-bound approval
    //    through the normal approval path BEFORE running it.
    const needsApproval = !!preview.approvalRequest;
    const approval = needsApproval
      ? await client.approve(action, input) // human/operator confirms
      : undefined;
    // 3) Run only after the dry-run (and approval, when required).
    const result = await client.run(action, input, { approval });
    if (!result.ok) throw new Error('action failed: ' + action);
  }

  // Assurance comes from the verifier, never asserted by this code.
  return { ok: true };
}

